import React, { useState } from "react";
import "../index.css";

function CreateCapsule() {
  const [mediaFiles, setMediaFiles] = useState([]);

  const handleFileChange = (e, index) => {
    const files = [...mediaFiles];
    files[index] = e.target.files[0];
    setMediaFiles(files);
  };

  const addMediaInput = () => {
    setMediaFiles([...mediaFiles, null]); // Add a new input field
  };

  const removeMediaInput = (index) => {
    const files = mediaFiles.filter((_, i) => i !== index);
    setMediaFiles(files);
  };

  return (
    <div>
      <h1>💖 Create a Time Capsule ✨</h1>

      <div className="form-container">
        <input type="text" placeholder="Title" />
        <input type="date" />
        <textarea placeholder="Write your message..."></textarea>

        {/* File Upload Inputs */}
        {mediaFiles.map((file, index) => (
          <div key={index} className="file-input-container">
            <input 
              type="file" 
              accept="image/*, video/*, audio/*" 
              onChange={(e) => handleFileChange(e, index)}
            />
            <button className="remove-btn" onClick={() => removeMediaInput(index)}>❌</button>
          </div>
        ))}

        {/* Button to Add More Media */}
        <button className="add-media-btn" onClick={addMediaInput}>➕ Add More Media</button>

        <button className="create-btn">Create Capsule</button>
      </div>
    </div>
  );
}

export default CreateCapsule;
